() => {
  const selectEl = document.querySelector("gs-select[data-qa-id='vehicleTypes']");
  const pop = document.querySelector("gs-select-popover");
  if (!selectEl || !pop) return;

  const pane = pop.closest('.cdk-overlay-pane');
  if (!pane) return;

  const r = selectEl.getBoundingClientRect();
  const gap = 6;

  pane.style.position = 'fixed';
  pane.style.left = `${Math.round(r.left)}px`;
  pane.style.top = `${Math.round(r.bottom + gap)}px`;
  pane.style.transform = 'none';
  pane.style.minWidth = `${Math.max(400, Math.round(r.width))}px`;
  pane.style.margin = '0';
  pane.style.zIndex = '10000';
}
